// schedulingEngine.js

const cron = require('node-cron');
const mongoose = require('mongoose');
const NotificationLog = require('../models/NotificationLog');
const Task = require('../models/Task');
const { sendNotification } = require('../services/notificationService');
require('dotenv').config();

/**
 * Schedule tasks for notifications based on recurrence settings.
 */
function scheduleTasks() {
  // Fetch all active tasks from the database
  Task.find({ status: 'active' })
    .then(tasks => {
      tasks.forEach(task => {
        const { recurrence } = task;
        const cronTime = getCronTime(recurrence);
        // Schedule the task using node-cron
        cron.schedule(cronTime, () => {
          handleTaskNotification(task);
        }, {
          scheduled: true,
          timezone: 'UTC'
        });
      });
    })
    .catch(err => console.error('Error fetching tasks:', err));
}

/**
 * Get a cron time string based on the recurrence object.
 * @param {Object} recurrence - The recurrence details of the task.
 * @returns {String} - The cron time string.
 */
function getCronTime(recurrence) {
  if (recurrence.type === 'daily') {
    return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * *`;
  } else if (recurrence.type === 'weekly' && recurrence.daysOfWeek) {
    const days = recurrence.daysOfWeek.map(day => day - 1).join(',');
    return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * ${days}`;
  }
  // Handle 'custom' or other types in the future
  return '*/1 * * * *'; // Default every minute (for testing)
}

/**
 * Handle the notification process for a specific task.
 * @param {Object} task - The task object.
 */
function handleTaskNotification(task) {
  const { rotationIndex, assignees } = task;
  let assignee = assignees[rotationIndex];
  // Check for unavailable members and adjust rotation index
  while (task.unavailableMembers.includes(assignee)) {
    task.rotationIndex = (task.rotationIndex + 1) % assignees.length;
    assignee = assignees[task.rotationIndex];
  }
  sendNotification(assignee, task)
    .then(() => {
      // Log the successful notification
      NotificationLog.create({
        taskId: task.id,
        sentAt: new Date(),
        status: 'success',
        retryCount: 0
      });
    })
    .catch(err => {
      console.error('Failed to send notification:', err);
      NotificationLog.create({
        taskId: task.id,
        sentAt: new Date(),
        status: 'failed',
        errorDetails: err.message,
        retryCount: 1
      });
    });
}

// Initialize the scheduling engine
scheduleTasks();

module.exports = scheduleTasks;
